#include <bits/stdc++.h>
using namespace std;
vector<int> g[100005];
int n,m,c[100005],ans1,ans2,sum1,sum2;
void dfs(int x){
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(!c[g[x][i]]){
            c[g[x][i]]=(c[x]==1? 2:1);
            if(c[g[x][i]]==1)sum1++;
            else sum2++;
            dfs(g[x][i]);
        }
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        if(!c[i]){
            c[i]=1,sum1=1,sum2=0;
            dfs(i);
            ans1+=min(sum1,sum2),ans2+=max(sum1,sum2);
        }
    cout<<ans1<<' '<<ans2;
    return 0;
}
